+import {Options, RuleType} from '../rules';
+import RuleBuilder, {ExampleBuilder, OptionBuilderBase} from './rule-builder';
+
+type ListStyle = 'bullet' | 'number';
+type OrderedListStyle = 'always-one' | 'increment';
+
+class AutoTocOptions implements Options {
+  listStyle: ListStyle = 'bullet';
+  bulletMarker: string = '-';
+  orderedListStyle: OrderedListStyle = 'always-one';
+  indentSize: number = 2;
+  minLevel: number = 2;
+  maxLevel: number = 6;
+  title: string = '';
+  useExplicitIds: boolean = false;
+  stripFormattingInToc: boolean = false;
+  excludeHeadings: string[] = [];
+}
+
+type Heading = {level: number, text: string, anchor: string};
+
+const startMarker = /<!--\\s*toc\\s*-->/i;
+const endMarker = /<!--\\s*\\/toc\\s*-->/i;
+const atxHeading = /^(?: {0,3})(#{1,6})(?:[ \	]+(.*?)\\s*|[ \	]*)$/;
+
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.CONTENT,
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const start = startMarker.exec(text);
+    if (!start) return text;
+
+    const startEnd = start.index + start[0].length;
+    const afterStart = text.slice(startEnd);
+    const end = endMarker.exec(afterStart);
+    const regionEnd = end ? startEnd + end.index + end[0].length : text.length;
+    const headings = getHeadings(text, start.index, regionEnd, options);
+    const toc = buildToc(start[0], end?.[0] ?? '<!-- /toc -->', headings, options);
+
+    // Consume existing blank lines after the old region: the generated TOC owns
+    // the required blank line after its closing marker.
+    const rest = text.slice(regionEnd).replace(/^\
+/, '');
+    return text.slice(0, start.index) + toc + rest;
+  }
+
+  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
+    return [];
+  }
+
+  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
+    return [];
+  }
+}
+
+function getHeadings(text: string, tocStart: number, tocEnd: number, options: AutoTocOptions): Heading[] {
+  const headings: Heading[] = [];
+  const usedAnchors = new Map<string, number>();
+  let offset = 0;
+  let inYaml = false;
+  let yamlChecked = false;
+  let fence: string = null;
+  let inMath = false;
+
+  for (const line of text.split('\
')) {
+    const lineStart = offset;
+    const lineEnd = offset + line.length;
+    offset = lineEnd + 1;
+
+    if (!yamlChecked) {
+      yamlChecked = true;
+      if (line === '---') {
+        inYaml = true;
+        continue;
+      }
+    }
+    if (inYaml) {
+      if (line === '---' || line === '...') inYaml = false;
+      continue;
+    }
+
+    const fenceMatch = /^( {0,3})(`{3,}|~{3,})/.exec(line);
+    if (fence) {
+      if (fenceMatch && fenceMatch[2][0] === fence[0] && fenceMatch[2].length >= fence.length) fence = null;
+      continue;
+    }
+    if (fenceMatch) {
+      fence = fenceMatch[2];
+      continue;
+    }
+    if (/^ {0,3}\\$\\$\\s*$/.test(line)) {
+      inMath = !inMath;
+      continue;
+    }
+    if (inMath || (lineStart >= tocStart && lineEnd <= tocEnd)) continue;
+
+    const match = atxHeading.exec(line);
+    if (!match) continue;
+    const level = match[1].length;
+    if (level < options.minLevel || level > options.maxLevel) continue;
+
+    const headingText = match[2] ?? '';
+    if (isExcluded(headingText, options.excludeHeadings)) continue;
+    const explicitId = options.useExplicitIds ? /\\s*\\{#([^}\\s]+)\\}\\s*$/.exec(headingText) : null;
+    const visibleText = explicitId ? headingText.slice(0, explicitId.index).trimEnd() : headingText;
+    const baseAnchor = explicitId?.[1] ?? anchorFromHeading(visibleText);
+    const count = usedAnchors.get(baseAnchor) ?? 0;
+    usedAnchors.set(baseAnchor, count + 1);
+    headings.push({
+      level,
+      text: options.stripFormattingInToc ? displayText(visibleText) : visibleText,
+      anchor: count === 0 ? baseAnchor : `${baseAnchor}-${count}`,
+    });
+  }
+  return headings;
+}
+
+function buildToc(start: string, end: string, headings: Heading[], options: AutoTocOptions): string {
+  const lines = headings.map((heading, index) => {
+    const indentation = ' '.repeat(Math.max(0, heading.level - options.minLevel) * Math.max(0, options.indentSize));
+    const marker = options.listStyle === 'number'
+      ? `${options.orderedListStyle === 'increment' ? index + 1 : 1}.`
+      : options.bulletMarker;
+    return `${indentation}${marker} [${heading.text}](#${heading.anchor})`;
+  });
+  const body = [start, '', ...(options.title ? [options.title, ''] : []), ...lines, '', end, '', ''];
+  return body.join('\
');
+}
+
+function anchorFromHeading(heading: string): string {
+  return displayText(heading)
+      .replace(/\\s+#+\\s*$/, '')
+      .toLowerCase()
+      .replace(/\\s+/g, '-')
+      .replace(/[^a-z0-9-_]/g, '')
+      .replace(/-+/g, '-')
+      .replace(/^-+|-+$/g, '');
+}
+
+function displayText(text: string): string {
+  return text
+      .replace(/!\\[\\[[^\\]]*\\]\\]/g, '')
+      .replace(/!\\[[^\\]]*\\]\\([^)]*\\)/g, '')
+      .replace(/\\[\\[([^\\]|]+)\\|([^\\]]+)\\]\\]/g, '$2')
+      .replace(/\\[\\[([^\\]]+)\\]\\]/g, '$1')
+      .replace(/\\[([^\\]]+)\\]\\([^)]*\\)/g, '$1')
+      .replace(/[`*_~]/g, '')
+      .replace(/<[^>]*>/g, '')
+      .trim();
+}
+
+function isExcluded(heading: string, exclusions: string[]): boolean {
+  const candidate = displayText(heading);
+  return exclusions.some((exclusion) => {
+    if (exclusion.length > 2 && exclusion.startsWith('/') && exclusion.endsWith('/')) {
+      try {
+        return new RegExp(exclusion.slice(1, -1), 'i').test(candidate);
+      } catch (_) {
+        // Treat malformed regexes as literals so an invalid preference never breaks linting.
+      }
+    }
+    return candidate.localeCompare(exclusion, undefined, {sensitivity: 'accent'}) === 0;
+  });
+}
